section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/python-fastapi",
  "type": "object",
  "required": ["app", "lifespan", "schemas", "deps"],
  "properties": {
    "app": {
      "type": "object",
      "properties": {
        "module": {"const": "app.main"},
        "title": {"type": "string"}
      }
    },
    "lifespan": {
      "type": "object",
      "properties": {
        "uses": {"const": "asynccontextmanager"},
        "deprecated_on_event": {"const": false}
      }
    },
    "schemas": {
      "type": "array",
      "description": "Each entity must have Base + Create + Update + Response.",
      "items": {"type": "string", "pattern": ".*(Base|Create|Update|Response)$"}
    },
    "deps": {
      "type": "object",
      "properties": {
        "DBSession": {"const": "Annotated[AsyncSession, Depends(get_db)]"},
        "CurrentUser": {"const": "Annotated[User, Depends(get_current_user)]"}
      }
    }
  }
}

example.code:
@app.on_event("startup") # r1 deprecated async def startup(): ...
class User(BaseModel): # r2 one schema fits all id: int password: str
@router.post("/users") def create_user(payload: User, db: Session = Depends(get_db)): # r3 no alias, r4 sync def db.execute("INSERT INTO users...") # SQL in router, no service return {"id": 1} # dict, not ORM
